// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Tasker Modal - Save as Draft
//------------------------------------------------------------------------------------------------------------------------
// 2.8 | 2022-07-04 | raj | STRY0121023 - Org Hierarchy- Favorited OU button- Add Warning Dialogue for users in a different Top OU
//                          New Widget 
// 2.8 | 2022-06-28 | raj | STRY0121017 - Org Hierarchy- Default OU button- Add Warning Dialogue for users in a different Top OU
//                          New Widget 
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
	main();

	function main() {
		data.favoriteOU = (input || {}).favoriteOU || (options || {}).favoriteOU || false;
		data.defaultOU = (input || {}).defaultOU || (options || {}).defaultOU || false;
		_buildMessages();
		_setDataDefaults();
	}

	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');
		data.submitButtonText = gs.getMessage('Tasker - Button - Confirm');

		data.msgBody2i = gs.getMessage('Information Notice');

		data.msgBody3 = gs.getMessage('Tasker - You are about to navigate to your Favorite OU');
		data.msgBody3i = gs.getMessage('Tasker - You are about to navigate to your Default OU');

		data.msgBody4 = gs.getMessage('Tasker - This will navigate you away from the current Organizational Tree');

		data.msgBody5 = gs.getMessage('Tasker - Are you sure you would like to continue?');

		data.msgBody6 = gs.getMessage("Tasker - Don't show this message again.");
	}
	// copy to data from input or options
	function _optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	function _setDataDefaults() {
		data.submit = false;
	}
})($sp, input, data, options);
